import { Layer, Source } from '@vis.gl/react-maplibre';

import { SorterIcon } from '@dynatrace/strato-icons';

import { parseDirectionDataToGeoJSON } from './utils/parse-direction-data-to-geo-json.js';
import {
  DIRECTION_ICON_OUTPUT_SIZE,
  DIRECTION_ICON_SHRINK_RATIO,
  SHAPE_OPACITY_DEFAULT,
  SHAPE_OPACITY_DIMMED,
} from '../../constants.js';
import { useLoadSymbolIntoMap } from '../../hooks/use-load-symbol-into-map.js';
import type {
  Connection,
  InternalConnectionLayerProps,
} from '../../types/connection-layer.js';

interface ConnectionLayerDirectionProps<T extends Connection>
  extends Required<
    Pick<InternalConnectionLayerProps<T>, 'layerId' | 'directionIndicator'>
  > {
  geoJsonData: GeoJSON.FeatureCollection;
}

export const ConnectionLayerDirection = <T extends Connection>(
  props: ConnectionLayerDirectionProps<T>,
) => {
  const { geoJsonData, layerId: connectionLayerId, directionIndicator } = props;

  const layerId = `${connectionLayerId}-direction`;
  const sourceId = `source-${layerId}`;

  // To get an image with enough quality instead of creating a tiny pic
  // and enlarge it, we create a huge image to shrink it
  const { symbolName } = useLoadSymbolIntoMap(
    <SorterIcon />,
    layerId,
    DIRECTION_ICON_OUTPUT_SIZE,
  );

  const parsedGeoJsonData = parseDirectionDataToGeoJSON({
    geoJsonData,
    directionIndicator,
  });

  /**
   * This value is necessary due to the icon
   * that comes from the '\@dynatrace/strato-icons'
   * SorterIcon points downwards, but it should point upwards
   * for the sake of the angle calculation.
   */
  const iconRotationDegrees = 180;

  return (
    <Source
      id={sourceId}
      type="geojson"
      data={parsedGeoJsonData}
      promoteId="id"
    >
      <Layer
        id={layerId}
        beforeId={connectionLayerId}
        type="symbol"
        layout={{
          'symbol-placement': 'point',
          'icon-image': symbolName,
          'icon-rotate': ['+', ['get', '__angle'], iconRotationDegrees],
          'icon-rotation-alignment': 'map',
          'icon-allow-overlap': true,
          'icon-ignore-placement': true,
          'icon-size': [
            '*',
            ['get', '__lineWidth'],
            DIRECTION_ICON_SHRINK_RATIO,
          ],
        }}
        paint={{
          'icon-color': [
            'case',
            ['boolean', ['feature-state', 'hover'], false],
            ['get', '__lineHoveredColor'],
            ['get', '__lineColor'],
          ],
          'icon-opacity': [
            'case',
            ['boolean', ['feature-state', 'legendHover'], true],
            SHAPE_OPACITY_DEFAULT,
            SHAPE_OPACITY_DIMMED,
          ],
        }}
      />
    </Source>
  );
};

ConnectionLayerDirection['displayName'] = 'ConnectionLayerDirection';
